<style>
@import url('https://fonts.cdnfonts.com/css/cal-sans');

.marquee-container {
  width: 100%;
  overflow: hidden;
  position: relative;
  background: none;
}

.marquee-container::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 100%;
  height: 180px; /* sfumatura */
  background: linear-gradient(to top, white 0%, transparent 70%);
  pointer-events: none;
}

.marquee {
  display: inline-block;
  white-space: nowrap;
  padding-left: 100%;
  animation: scroll-left 25s linear infinite;
  font-family: 'Cal Sans', sans-serif;
  font-size: 70px; /* metà dimensione attuale per mobile */
  font-weight: 500;
  color: #000;
}

.marquee span {
  display: inline-block;
  margin-right: 60px;
}

.marquee .divider {
  width: 25px;
  height: auto;
  vertical-align: middle;
  margin: 0 40px;
}

@keyframes scroll-left {
  0% { transform: translateX(0); }
  100% { transform: translateX(-100%); }
}
</style>
