    width: max-content;
    animation: marquee-scroll 45s linear infinite;
  }

  .marquee {
    display: flex;
    align-items: center;
    gap: 40px;
    white-space: nowrap;
    padding-right: 40px;
  }

  .marquee span {
    font-size: 34px;
    font-weight: 600;
    color: #000;
  }

  .marquee .orange {
    color: #f36a21;
  }

  .marquee .black {
    color: #000;
  }

  .marquee .divider {
    width: 34px;
    height: auto;
  }

  @keyframes marquee-scroll {
    from {
      transform: translateX(0);
    }
    to {
      transform: translateX(-50%);
