  <span class="word w1">Visione</span>
  <span class="word w2">Strategia</span>
  <span class="word w3">Design</span>
  <span class="word w4">Performance</span>
</div>

<style>
@import url('https://fonts.cdnfonts.com/css/cal-sans');

/* Contenitore regolato per font 90px */
.word-rotator {
  position: relative;
  width: 100%;
  height: 150px; /* aumentato per il font grande */
  text-align: center;
  font-family: 'Cal Sans', sans-serif;
  font-weight: 600;
  font-size: 90px; /* FONT RICHIESTO */
  overflow: hidden;
  line-height: 150px; /* centra verticalmente */
}

/* Parole sovrapposte */
.word {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  opacity: 0;
  animation: wordFade 12s infinite;
  white-space: nowrap;
}

/* Colori alternati */
.w1 { color: #FF6A00; animation-delay: 0s; }
.w2 { color: #000000; animation-delay: 3s; }
.w3 { color: #7A7A7A; animation-delay: 6s; }
.w4 { color: #FF6A00; animation-delay: 9s; }

@keyframes wordFade {
  0%   { opacity: 0; transform: translate(-50%, -20px); }
  8%   { opacity: 1; transform: translate(-50%, -50%); }
  25%  { opacity: 1; transform: translate(-50%, -50%); }
  33%  { opacity: 0; transform: translate(-50%, 20px); }
  100% { opacity: 0; }
}
</style>
