<style>
@import url('https://fonts.cdnfonts.com/css/cal-sans');

.word-rotator {
  position: relative;
  width: 100%;
  height: 130px;          /* altezza contenitore desktop */
  text-align: center;
  font-family: 'Cal Sans', sans-serif;
  font-weight: 600;
  font-size: 110px !important;   /* dimensione desktop grande e forzata */
  overflow: hidden;
  line-height: 130px !important;
}

.word {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
  opacity: 0;
  animation: wordFade 21s infinite;
  white-space: nowrap;
}

/* Colori alternati */
.w1 { color: #FF6A00; animation-delay: 0s; }
.w2 { color: #000000; animation-delay: 3s; }
.w3 { color: #7A7A7A; animation-delay: 6s; }
.w4 { color: #FF6A00; animation-delay: 9s; }
.w5 { color: #000000; animation-delay: 12s; }
.w6 { color: #7A7A7A; animation-delay: 15s; }
.w7 { color: #FF6A00; animation-delay: 18s; }

@keyframes wordFade {
  0%   { opacity: 0; transform: translate(-50%, -20px); }
  5%   { opacity: 1; transform: translate(-50%, -50%); }
  15%  { opacity: 1; transform: translate(-50%, -50%); }
  18%  { opacity: 0; transform: translate(-50%, 20px); }
  100% { opacity: 0; }
}

/* 📱 MOBILE */
@media (max-width: 768px) {
  .word-rotator {
    font-size: 65px !important;    /* dimensione mobile ridotta e forzata */
    height: 80px !important;
    line-height: 80px !important;
  }
}
</style>
