<style>
.logo-container {
  width: 300px;       /* puoi modificare la larghezza del container */
  height: 300px;      /* puoi modificare l'altezza del container */
  display: flex;
  justify-content: center; /* centra orizzontalmente */
  align-items: center;     /* centra verticalmente */
  margin: 0 auto;          /* centra il container nella pagina */
  overflow: hidden;        /* evita eventuali tagli del logo */
}

/* Ruota continuamente il logo */
.rotating-logo {
  width: 80%;        /* dimensione del logo rispetto al container */
  height: auto;
  animation: rotateLogo 5s linear infinite;
}

/* Animazione di rotazione */
@keyframes rotateLogo {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}
</style>
